1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	  moonstone: 25,
24	};
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const BLOCK_SIZE = 3;
28	const BLOCK_PREMIUM = 60;
29	
30	const FIRST_INSURANCE_SURCHARGE = 0.1;
31	const PROCESSING_FEE = 5;
32	
33	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
34	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
35	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
36	
37	// A block applies only to a group of exactly BLOCK_SIZE alike components,
38	// priced at BLOCK_PREMIUM; any other count is priced individually.
39	const componentBasePremium = (count: number, perComponent: number): number => {
40	  if (count === BLOCK_SIZE) return BLOCK_PREMIUM;
41	  return count * perComponent;
42	};
43	
44	const sum = (amounts: number[]): number => amounts.reduce((acc, amount) => acc + amount, 0);
45	
46	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
47	const isMainItem = (item: Item): boolean => !isComponent(item);
48	
49	const countByType = (items: Item[]): Record<string, number> => {
50	  const counts: Record<string, number> = {};
51	  for (const item of items) {
52	    counts[item.type] = (counts[item.type] ?? 0) + 1;
53	  }
54	  return counts;
55	};
56	
57	const itemsBasePremium = (items: Item[]): number => {
58	  const mainItems = items.filter(isMainItem);
59	  const componentCounts = countByType(items.filter(isComponent));
60	
61	  const mainItemsPremium = sum(mainItems.map((item) => BASE_PREMIUM[item.type]));
62	  const componentsPremium = sum(
63	    Object.entries(componentCounts).map(([type, count]) =>
64	      componentBasePremium(count, BASE_PREMIUM[type]),
65	    ),
66	  );
67	
68	  return mainItemsPremium + componentsPremium;
69	};
70	
71	const quotePremium = (items: Item[]): number => {
72	  const itemsPremium = itemsBasePremium(items) * (1 + FIRST_INSURANCE_SURCHARGE);
73	  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
74	};
75	
76	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
77	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
78	  return { results };
79	};
